import logging
from flask import Flask, request

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='web_app.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

@app.route('/log', methods=['POST'])
def log_message():
    data = request.json
    if not data or 'message' not in data:
        return "Invalid request", 400
    
    message = data['message']
    
    # Prevent log injection by escaping special characters
    safe_message = message.replace('\n', '\\n').replace('\r', '\\r').replace('\t', '\\t')
    
    logging.info(safe_message)
    
    return "Log message received", 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)